targets.expr:
(
  1 - (
    hostedClusterAPI_kubeapiserver_available:sli_sum_15m{cluster=~"$cluster", namespace=~"$namespace"}
    /
    hostedClusterAPI_kubeapiserver_available:sli_count_15m{cluster=~"$cluster", namespace=~"$namespace"}
  )
) / (1 - 0.9995)

(
  1 - (
    hostedClusterAPI_kubeapiserver_available:sli_sum_6h{cluster=~"$cluster", namespace=~"$namespace"}
    /
    hostedClusterAPI_kubeapiserver_available:sli_count_6h{cluster=~"$cluster", namespace=~"$namespace"}
  )
) / (1 - 0.9995)

(
  sum by (namespace) (
    kas:apiserver_request_5xx:rate_avg_1h{cluster=~"$cluster", namespace=~"$namespace"}
  )
  /
  sum by (namespace) (
    kas:apiserver_request_total:rate_avg_1h{cluster=~"$cluster", namespace=~"$namespace"}
  )
) / (1 - 0.9995)

(
  sum by (namespace) (
    kas:apiserver_request_5xx:rate_avg_6h{cluster=~"$cluster", namespace=~"$namespace"}
  )
  /
  sum by (namespace) (
    kas:apiserver_request_total:rate_avg_6h{cluster=~"$cluster", namespace=~"$namespace"}
  )
) / (1 - 0.9995)

sum by (namespace) (
  rate(apiserver_request_sli_duration_seconds_bucket{
    cluster=~"$cluster", namespace=~"$namespace",
    verb=~"POST|PUT|PATCH|DELETE",
    scope=~"resource|namespace|cluster",
    subresource!~"proxy|attach|log|exec|portforward",
    le="1.0"
  }[$__rate_interval])
)
/
sum by (namespace) (
  rate(apiserver_request_sli_duration_seconds_count{
    cluster=~"$cluster", namespace=~"$namespace",
    verb=~"POST|PUT|PATCH|DELETE",
    scope=~"resource|namespace|cluster",
    subresource!~"proxy|attach|log|exec|portforward"
  }[$__rate_interval])
)

sum by (namespace) (
